SELECT average_rating
FROM review_statistics
WHERE product_id = '0';

SELECT COUNT(*) AS downvote_count
FROM review_votes
WHERE review_id = 0 AND vote_type = 'downvote';

SELECT review_id, sentiment_score
FROM reviews
ORDER BY sentiment_score DESC;

SELECT COUNT(*) AS report_count
FROM review_reports
WHERE report_reason = 'Inappropriate content';

SELECT MAX(total_reviews) AS max_reviews
FROM (
  SELECT product_id, COUNT(review_id) AS total_reviews
  FROM reviews
  GROUP BY product_id
) AS review_counts;

SELECT COUNT(review_id) AS total_reviews
FROM user_reviews
WHERE user_id = 0;
